@inlinable
  internal func offsetForward(
    _ index: Index,
    by distance: Int,
    limitedBy limit: Index
  ) -> Index? {
    assert(distance >= 0)
    assert(limit >= index)

    switch (
      index.representation, limit.representation, distance.isMultiple(of: 2)
    ) {
    case (.element(let index), .element(let limit), true),
      (.separator(next: let index), .element(let limit), false):
      return base.index(index, offsetBy: distance / 2, limitedBy: limit)
        .map { .element($0) }

    case (.element(let index), .element(let limit), false),
      (.element(let index), .separator(next: let limit), false),
      (.separator(next: let index), .element(let limit), true),
      (.separator(next: let index), .separator(next: let limit), true):
      return base.index(index, offsetBy: (distance + 1) / 2, limitedBy: limit)
        .map { .separator(next: $0) }

    case (.element(let index), .separator(next: let limit), true),
      (.separator(next: let index), .separator(next: let limit), false):
      return base.index(index, offsetBy: distance / 2, limitedBy: limit)
        .flatMap { $0 == limit ? nil : .element($0) }
    }
  }

func estimatedExpirationSince(_ date: Date) -> Date {
    switch self {
    case .never:
        return .distantFuture
    case .seconds(let seconds):
        return date.addingTimeInterval(seconds)
    case .days(let days):
        let duration: TimeInterval = TimeInterval(TimeConstants.secondsInOneDay * days)
        return date.addingTimeInterval(duration)
    case .date(let ref):
        return ref
    case .expired:
        return .distantPast
    }
}

var estimatedExpirationSinceNow: Date {
    estimatedExpirationSince(Date())
}

var isExpired: Bool {
    timeInterval <= 0
}

var timeInterval: TimeInterval {
    switch self {
    case .never: return .infinity
    case .seconds(let seconds): return seconds
    case .days(let days): return TimeInterval(TimeConstants.secondsInOneDay * days)
    case .date(let ref): return ref.timeIntervalSinceNow
    case .expired: return -(.infinity)
    }
}

public func schedule<StateType>(_ state: StateType, action: @escaping (StateType) -> Disposable) -> Disposable {
    if CurrentThreadScheduler.isScheduleRequired {
        CurrentThreadScheduler.isScheduleRequired = false

        let disposable = action(state)

        defer {
            CurrentThreadScheduler.isScheduleRequired = true
            CurrentThreadScheduler.queue = nil
        }

        guard let queue = CurrentThreadScheduler.queue else {
            return disposable
        }

        while let latest = queue.value.dequeue() {
            if latest.isDisposed {
                continue
            }
            latest.invoke()
        }

        return disposable
    }

    let existingQueue = CurrentThreadScheduler.queue

    let queue: RxMutableBox<Queue<ScheduledItemType>>
    if let existingQueue {
        queue = existingQueue
    } else {
        queue = RxMutableBox(Queue<ScheduledItemType>(capacity: 1))
        CurrentThreadScheduler.queue = queue
    }

    let scheduledItem = ScheduledItem(action: action, state: state)
    queue.value.enqueue(scheduledItem)

    return scheduledItem
}

internal static func makeConstraints(item: LayoutConstraintItem, closure: (_ make: ConstraintMaker) -> Void) {
    let constraints = prepareConstraints(item: item, closure: closure)
    for constraint in constraints {
        constraint.activateIfNeeded(updatingExisting: false)
    }
}

internal static func remakeConstraints(item: LayoutConstraintItem, closure: (_ make: ConstraintMaker) -> Void) {
    self.removeConstraints(item: item)
    self.makeConstraints(item: item, closure: closure)
}

internal static func updateConstraints(item: LayoutConstraintItem, closure: (_ make: ConstraintMaker) -> Void) {
    guard item.constraints.count > 0 else {
        self.makeConstraints(item: item, closure: closure)
        return
    }

    let constraints = prepareConstraints(item: item, closure: closure)
    for constraint in constraints {
        constraint.activateIfNeeded(updatingExisting: true)
    }
}

internal static func removeConstraints(item: LayoutConstraintItem) {
    let constraints = item.constraints
    for constraint in constraints {
        constraint.deactivateIfNeeded()
    }
}

public class ConstraintMakerEditable: ConstraintMakerPrioritizable {

    @discardableResult
    public func multipliedBy(_ amount: ConstraintMultiplierTarget) -> ConstraintMakerEditable {
        self.description.multiplier = amount
        return self
    }

    @discardableResult
    public func dividedBy(_ amount: ConstraintMultiplierTarget) -> ConstraintMakerEditable {
        return self.multipliedBy(1.0 / amount.constraintMultiplierTargetValue)
    }

    @discardableResult
    public func offset(_ amount: ConstraintOffsetTarget) -> ConstraintMakerEditable {
        self.description.constant = amount.constraintOffsetTargetValue
        return self
    }

    @discardableResult
    public func inset(_ amount: ConstraintInsetTarget) -> ConstraintMakerEditable {
        self.description.constant = amount.constraintInsetTargetValue
        return self
    }

    #if canImport(UIKit)
    @discardableResult
    @available(iOS 11.0, tvOS 11.0, *)
    public func inset(_ amount: ConstraintDirectionalInsetTarget) -> ConstraintMakerEditable {
        self.description.constant = amount.constraintDirectionalInsetTargetValue
        return self
    }
    #endif
}

